import{_ as r,c as o,o as i,a5 as t,j as e}from"./chunks/framework.Dtwt352Q.js";const m=JSON.parse('{"title":"v1.1.14: Major TUI Interaction Upgrade","description":"","frontmatter":{},"headers":[],"relativePath":"en/changelog/v1.1.14.md","filePath":"en/changelog/v1.1.14.md","lastUpdated":1772014034000}'),n={name:"en/changelog/v1.1.14.md"};function s(l,a,h,d,c,u){return i(),o("div",null,[...a[0]||(a[0]=[t('<h1 id="v1-1-14-major-tui-interaction-upgrade" tabindex="-1">v1.1.14: Major TUI Interaction Upgrade <a class="header-anchor" href="#v1-1-14-major-tui-interaction-upgrade" aria-label="Permalink to ‚Äúv1.1.14: Major TUI Interaction Upgrade‚Äù">‚Äã</a></h1><p><strong>Release Date</strong>: January 12, 2026</p><hr><h2 id="one-line-summary" tabindex="-1">One-Line Summary <a class="header-anchor" href="#one-line-summary" aria-label="Permalink to ‚ÄúOne-Line Summary‚Äù">‚Äã</a></h2><p>This update makes <strong>TUI terminal interface mouse interaction smoother</strong>, autocomplete and Q&amp;A options all support mouse hover and click, plus fixes cursor position error when pasting text.</p><hr><h2 id="new-feature-comprehensive-mouse-interaction-upgrade" tabindex="-1">New Feature: Comprehensive Mouse Interaction Upgrade <a class="header-anchor" href="#new-feature-comprehensive-mouse-interaction-upgrade" aria-label="Permalink to ‚ÄúNew Feature: Comprehensive Mouse Interaction Upgrade‚Äù">‚Äã</a></h2><h3 id="what-s-updated" tabindex="-1">What&#39;s Updated? <a class="header-anchor" href="#what-s-updated" aria-label="Permalink to ‚ÄúWhat&#39;s Updated?‚Äù">‚Äã</a></h3><p>TUI (terminal interface) now supports more mouse operations:</p><ul><li><strong>Autocomplete</strong>: Mouse hover highlight, click to select</li><li><strong>Q&amp;A options</strong>: Mouse hover highlight, click to select</li><li><strong>Subagent titles</strong>: Click to navigate</li></ul><h3 id="why-is-this-important" tabindex="-1">Why Is This Important? <a class="header-anchor" href="#why-is-this-important" aria-label="Permalink to ‚ÄúWhy Is This Important?‚Äù">‚Äã</a></h3><p>Previously in TUI, many operations were keyboard-only. Now you can:</p><ol><li>Click autocomplete options with mouse, no arrow keys needed</li><li>Click Q&amp;A options with mouse, no number input needed</li><li>Click subagent titles to quickly view details</li></ol><p><strong>Simply put</strong>: Keyboard users keep using keyboard, mouse users can also enjoy it now.</p><hr><h2 id="bug-fix-pasted-text-cursor-position-correct" tabindex="-1">Bug Fix: Pasted Text Cursor Position Correct <a class="header-anchor" href="#bug-fix-pasted-text-cursor-position-correct" aria-label="Permalink to ‚ÄúBug Fix: Pasted Text Cursor Position Correct‚Äù">‚Äã</a></h2><h3 id="previous-issue" tabindex="-1">Previous Issue <a class="header-anchor" href="#previous-issue" aria-label="Permalink to ‚ÄúPrevious Issue‚Äù">‚Äã</a></h3><p>After pasting single-line text in TUI, cursor position would be in wrong place, causing text position issues when continuing to type.</p><h3 id="current-behavior" tabindex="-1">Current Behavior <a class="header-anchor" href="#current-behavior" aria-label="Permalink to ‚ÄúCurrent Behavior‚Äù">‚Äã</a></h3><p>Cursor correctly stops at text end after pasting, allowing smooth continued typing.</p><hr><h2 id="bug-fix-slash-command-autocomplete-no-longer-jumps" tabindex="-1">Bug Fix: Slash Command Autocomplete No Longer Jumps <a class="header-anchor" href="#bug-fix-slash-command-autocomplete-no-longer-jumps" aria-label="Permalink to ‚ÄúBug Fix: Slash Command Autocomplete No Longer Jumps‚Äù">‚Äã</a></h2><h3 id="previous-issue-1" tabindex="-1">Previous Issue <a class="header-anchor" href="#previous-issue-1" aria-label="Permalink to ‚ÄúPrevious Issue‚Äù">‚Äã</a></h3><p>After typing <code>/</code>, the autocomplete list highlight row would jump around inexplicably.</p><h3 id="current-behavior-1" tabindex="-1">Current Behavior <a class="header-anchor" href="#current-behavior-1" aria-label="Permalink to ‚ÄúCurrent Behavior‚Äù">‚Äã</a></h3><p>Highlight row is stable now, selecting commands is smoother.</p><hr><h2 id="other-improvements" tabindex="-1">Other Improvements <a class="header-anchor" href="#other-improvements" aria-label="Permalink to ‚ÄúOther Improvements‚Äù">‚Äã</a></h2><h3 id="desktop" tabindex="-1">Desktop <a class="header-anchor" href="#desktop" aria-label="Permalink to ‚ÄúDesktop‚Äù">‚Äã</a></h3><ul><li><strong>Image preview</strong>: Images in attachments can now be previewed directly, no need for external programs</li></ul><h3 id="core" tabindex="-1">Core <a class="header-anchor" href="#core" aria-label="Permalink to ‚ÄúCore‚Äù">‚Äã</a></h3><ul><li><strong>MCP tool output</strong>: Supports <code>resource</code> content type</li><li><strong>External directory permissions</strong>: More accurate subdirectory permission checking</li><li><strong>OAuth login</strong>: Automatically copies URL when device code unavailable</li></ul><hr><h2 id="should-you-upgrade" tabindex="-1">Should You Upgrade? <a class="header-anchor" href="#should-you-upgrade" aria-label="Permalink to ‚ÄúShould You Upgrade?‚Äù">‚Äã</a></h2><table tabindex="0"><thead><tr><th>Situation</th><th>Recommendation</th></tr></thead><tbody><tr><td>Frequently use TUI terminal interface</td><td>‚úÖ Upgrade, better experience</td></tr><tr><td>Previously encountered paste cursor issue</td><td>‚úÖ Upgrade</td></tr><tr><td>Mainly use Desktop</td><td>Can upgrade, has image preview</td></tr><tr><td>Everything works fine</td><td>Can wait for next time</td></tr></tbody></table><p><strong>Upgrade Command</strong>:</p>',36),e("div",{class:"language-bash"},[e("button",{title:"Copy Code",class:"copy"}),e("span",{class:"lang"},"bash"),e("pre",null,[e("code",{"v-pre":""},"opencode upgrade")])],-1),t('<hr><h2 id="technical-details-skippable" tabindex="-1">Technical Details (Skippable) <a class="header-anchor" href="#technical-details-skippable" aria-label="Permalink to ‚ÄúTechnical Details (Skippable)‚Äù">‚Äã</a></h2><details><summary>Click to expand full changelog</summary><h3 id="core-1" tabindex="-1">Core <a class="header-anchor" href="#core-1" aria-label="Permalink to ‚ÄúCore‚Äù">‚Äã</a></h3><ul><li>Support <code>resource</code> content type in MCP tool output (@antigremlin)</li><li>Check subdirectory external directory permissions (@dmmulroy)</li><li>Upgrade Copilot plugin version</li></ul><h3 id="tui" tabindex="-1">TUI <a class="header-anchor" href="#tui" aria-label="Permalink to ‚ÄúTUI‚Äù">‚Äã</a></h3><ul><li>Add click navigation for subagent titles</li><li>Q&amp;A tool supports mouse hover and click (@indeep99)</li><li>Fix prompt ref initialization, prevent undefined reference error</li><li>Refactor event stream, use SDK instead of manual RPC subscription</li><li>Fix cursor position when pasting single-line text (@Octane0411)</li><li>Autocomplete supports mouse hover and click (@kitlangton)</li><li>Copy OAuth URL when device code unavailable (@itskingori)</li><li>Fix slash command autocomplete highlight row jumping (@kitlangton)</li></ul><h3 id="desktop-1" tabindex="-1">Desktop <a class="header-anchor" href="#desktop-1" aria-label="Permalink to ‚ÄúDesktop‚Äù">‚Äã</a></h3><ul><li>Image attachment supports preview (@dbpolito)</li></ul><h3 id="community-contributors" tabindex="-1">Community Contributors <a class="header-anchor" href="#community-contributors" aria-label="Permalink to ‚ÄúCommunity Contributors‚Äù">‚Äã</a></h3><p>Thanks to 10 community contributors: @kitlangton, @itskingori, @zeke, @dbpolito, @jacobwgillespie, @dmmulroy, @Octane0411, @indeep99, @antigremlin, @eyalch</p></details><hr><p><a href="./">‚Üê Back to Changelog</a></p>',5)])])}const g=r(n,[["render",s]]);export{m as __pageData,g as default};
